empty = {
    "branch": "main",
    "staged": [],
    "modified": ["README.md"],
    "untracked": [],
}

def safe_to_commit(status):
    staged = status["staged"]
    for f in staged:
        if f.lower().startswith(".env"):
            return ("block", "secrets staged")
    if not staged:
        return ("block", "nothing staged")
    return ("ok", f"{len(staged)} files staged")

for case in [good, leak, empty]:
    verdict, reason = safe_to_commit(case)
    print(f"{verdict}: {reason}")

