    "secrets_in_env_vars_only": False,
}

def audit_repo(repo):
    score = 0
    risks = []
    if repo.get("has_gitignore_for_env"):
        score += 20
    else:
        risks.append("no .gitignore for .env — Uber-style leak possible")
    if repo.get("has_secret_scanning_hook"):
        score += 20
    else:
        risks.append("no pre-commit secret scanner — credentials can ship")
    if repo.get("reviewer_required_for_main"):
        score += 20
    else:
        risks.append("no required reviewer on main — agent pushes land unchecked")
    if not repo.get("agent_can_auto_commit"):
        score += 20
    else:
        risks.append("agent can auto-commit without diff review")
    if repo.get("secrets_in_env_vars_only"):
        score += 20
    else:
        risks.append("secrets not enforced env-only — inline creds are still possible")
    return {"score": score, "risks": risks}

print(f"{ai_startup_repo['name']}: {audit_repo(ai_startup_repo)}")
print(f"{legacy_monorepo['name']}: {audit_repo(legacy_monorepo)}")

