def score_one(repo):
    s = 0
    if repo.get("has_gitignore_for_env"):
        s += 20
    if repo.get("has_secret_scanning_hook"):
        s += 20
    if repo.get("reviewer_required_for_main"):
        s += 20
    if not repo.get("agent_can_auto_commit"):
        s += 20
    if repo.get("secrets_in_env_vars_only"):
        s += 20
